import React, { useState, useEffect, useMemo } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { 
  Plus, Trash2, Edit, ArrowLeft, Package, X, Save, 
  Loader2, Search, CheckCircle2, 
  Box, Layers, Send, Clock
} from 'lucide-react';

import GestionInventario from './GestionInventario'; 
import { generarNombreImagen } from '../utils/helpers';

const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();
  const [ofertas, setOfertas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showManual, setShowManual] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const [publishing, setPublishing] = useState(false);
  
  // Estado para las fechas de la oferta masiva
  const [fechasPublicacion, setFechasPublicacion] = useState({ inicio: '', fin: '' });

  const [nuevoProd, setNuevoProd] = useState({
    tipo: '', marca: '', contenido: '', categoria: 'Almacén',
    precioNuevo: '', precioViejo: '', stock: '', fechaVencimiento: ''
  });

  const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

  useEffect(() => { 
    if(localId) cargarOfertas(); 
  }, [localId]);

  const cargarOfertas = async () => {
    setLoading(true);
    try {
      const res = await axios.get(`${API_URL}/api/ofertas/local/${localId}`);
      setOfertas(res.data);
    } catch (e) { 
      console.error("Error cargando ofertas:", e); 
    }
    setLoading(false);
  };

  const handlePublicarTodo = async () => {
    if (!fechasPublicacion.inicio || !fechasPublicacion.fin) {
      alert("Por favor, selecciona las fechas de vigencia para el lote.");
      return;
    }

    setPublishing(true);
    try {
      await axios.put(`${API_URL}/api/ofertas/publicar-todo/${localId}`, {
        fechaInicio: fechasPublicacion.inicio,
        fechaFin: fechasPublicacion.fin
      });
      alert("¡Lote publicado con éxito!");
      cargarOfertas();
    } catch (err) {
      alert("Error al publicar el lote");
    } finally {
      setPublishing(false);
    }
  };

  const ofertasFiltradas = useMemo(() => {
    return ofertas.filter(o => 
      o.producto.toLowerCase().includes(searchTerm.toLowerCase()) ||
      o.categoria.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [ofertas, searchTerm]);

  const stats = useMemo(() => ({
    total: ofertas.length,
    sinStock: ofertas.filter(o => o.stock <= 0).length,
    pendientes: ofertas.filter(o => !o.publicado).length,
    publicadas: ofertas.filter(o => o.publicado).length
  }), [ofertas]);

  const handleCargaManual = async (e) => {
    e.preventDefault();
    try {
      const item = {
        ...nuevoProd,
        producto: `${nuevoProd.tipo} ${nuevoProd.marca} ${nuevoProd.contenido}`.trim(),
        publicId: generarNombreImagen(nuevoProd.tipo, nuevoProd.marca, nuevoProd.contenido),
        local: localId,
        precioNuevo: Number(nuevoProd.precioNuevo),
        precioViejo: Number(nuevoProd.precioViejo) || Number(nuevoProd.precioNuevo),
        stock: Number(nuevoProd.stock) || 0
      };
      
      await axios.post(`${API_URL}/api/ofertas`, item);
      setShowManual(false);
      setNuevoProd({ tipo: '', marca: '', contenido: '', categoria: 'Almacén', precioNuevo: '', precioViejo: '', stock: '', fechaVencimiento: '' });
      cargarOfertas();
    } catch (err) { 
      alert("Error al guardar el producto manual"); 
    }
  };

  return (
    <div style={containerStyle}>
      {/* Barra Superior */}
      <div style={topBar}>
        <button onClick={() => navigate('/dashboard')} style={btnBack}>
          <ArrowLeft size={18}/> Volver al Dashboard
        </button>
        <div style={badgeLocal}>ID Local: {localId?.slice(-6)}</div>
      </div>

      {/* Título */}
      <div style={headerStyle}>
        <div>
          <h1 style={titleStyle}>Panel de Inventario</h1>
          <p style={subtitleStyle}>Gestiona tus productos y define fechas de ofertas</p>
        </div>
        <button onClick={() => setShowManual(true)} style={btnPlus}>
          <Plus size={20}/> Nuevo Producto Manual
        </button>
      </div>

      {/* Indicadores */}
      <div style={statsGrid}>
        <div style={statCard}>
          <Box color="#3b82f6" />
          <div><span style={statNum}>{stats.total}</span><p style={statLabel}>Total</p></div>
        </div>
        <div style={{...statCard, borderLeft: '4px solid #f59e0b'}}>
          <Clock color="#f59e0b" />
          <div><span style={statNum}>{stats.pendientes}</span><p style={statLabel}>Por Publicar</p></div>
        </div>
        <div style={{...statCard, borderLeft: '4px solid #10b981'}}>
          <CheckCircle2 color="#10b981" />
          <div><span style={statNum}>{stats.publicadas}</span><p style={statLabel}>Publicadas</p></div>
        </div>
      </div>

      {/* CARGA RÁPIDA */}
      <GestionInventario localId={localId} onComplete={cargarOfertas} />

      {/* BARRA DE PUBLICACIÓN MASIVA */}
      {stats.pendientes > 0 && (
        <div style={publishBannerStyle}>
          <div style={publishInfo}>
            <div style={pendingCountBadge}>{stats.pendientes} pendientes</div>
            <div style={dateInputGroup}>
              <label style={dateLabel}>Válido desde:</label>
              <input type="date" style={dateInput} onChange={e => setFechasPublicacion({...fechasPublicacion, inicio: e.target.value})} />
            </div>
            <div style={dateInputGroup}>
              <label style={dateLabel}>Hasta:</label>
              <input type="date" style={dateInput} onChange={e => setFechasPublicacion({...fechasPublicacion, fin: e.target.value})} />
            </div>
          </div>
          <button style={btnPublicarMaster} onClick={handlePublicarTodo} disabled={publishing}>
            {publishing ? <Loader2 className="animate-spin"/> : <Send size={18}/>}
            Publicar Lote Completo
          </button>
        </div>
      )}

      {/* Buscador */}
      <div style={searchBarContainer}>
        <Search size={20} color="#94a3b8" style={searchIcon} />
        <input 
          style={searchInput} 
          placeholder="Buscar productos..." 
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      {/* Listado */}
      <div style={gridStyle}>
        {loading ? (
          <div style={loaderContainer}><Loader2 className="animate-spin" size={40} color="#e67e22"/></div>
        ) : ofertasFiltradas.length > 0 ? (
          ofertasFiltradas.map(o => (
            <div key={o._id} style={{...itemCard, opacity: o.publicado ? 1 : 0.85}}>
              <div style={cardHeader}>
                <div style={o.publicado ? badgePublicado : badgeBorrador}>
                   {o.publicado ? 'PUBLICADO' : 'BORRADOR'}
                </div>
                <div style={o.stock <= 0 ? badgeStockOut : badgeStockIn}>
                   {o.stock <= 0 ? 'SIN STOCK' : `Stock: ${o.stock}`}
                </div>
              </div>

              <div style={cardBody}>
                <h4 style={prodName}>{o.producto}</h4>
                <div style={categoryTag}><Layers size={12}/> {o.categoria}</div>
                
                <div style={priceContainer}>
                  <span style={currentPrice}>${o.precioNuevo}</span>
                  {o.precioViejo > o.precioNuevo && <span style={oldPrice}>${o.precioViejo}</span>}
                </div>
                {o.publicado && o.fechaFinOferta && (
                  <div style={dateBadge}>Vence: {new Date(o.fechaFinOferta).toLocaleDateString()}</div>
                )}
              </div>

              <div style={cardFooter}>
                <button style={btnActionEdit}><Edit size={16}/></button>
                <button 
                  style={btnActionDelete} 
                  onClick={async () => {
                    if(window.confirm(`¿Eliminar ${o.producto}?`)) {
                      await axios.delete(`${API_URL}/api/ofertas/${o._id}`);
                      cargarOfertas();
                    }
                  }}
                ><Trash2 size={16}/></button>
              </div>
            </div>
          ))
        ) : (
          <div style={emptyState}>
            <Package size={60} color="#e2e8f0" />
            <p>No hay productos registrados</p>
          </div>
        )}
      </div>

      {/* MODAL MANUAL */}
      {showManual && (
        <div style={modalOverlay}>
          <div style={modalContent}>
            <div style={modalHeader}>
              <h3 style={{margin:0}}>Registrar Producto</h3>
              <button onClick={() => setShowManual(false)} style={closeBtn}><X/></button>
            </div>
            <form onSubmit={handleCargaManual} style={formStyle}>
              <div style={inputRow}>
                <div style={inputGroup}><label style={labelS}>Tipo</label><input style={inputS} onChange={e => setNuevoProd({...nuevoProd, tipo: e.target.value})} required /></div>
                <div style={inputGroup}><label style={labelS}>Marca</label><input style={inputS} onChange={e => setNuevoProd({...nuevoProd, marca: e.target.value})} required /></div>
              </div>
              <div style={inputGroup}><label style={labelS}>Contenido</label><input style={inputS} onChange={e => setNuevoProd({...nuevoProd, contenido: e.target.value})} required /></div>
              <div style={inputRow}>
                <div style={inputGroup}><label style={labelS}>Precio</label><input style={inputS} type="number" onChange={e => setNuevoProd({...nuevoProd, precioNuevo: e.target.value})} required /></div>
                <div style={inputGroup}><label style={labelS}>Stock</label><input style={inputS} type="number" onChange={e => setNuevoProd({...nuevoProd, stock: e.target.value})} required /></div>
              </div>
              <button type="submit" style={btnSave}><Save size={18}/> Guardar en Base de Datos</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

// --- ESTILOS DEFINIDOS ---
const containerStyle = { padding: '40px', maxWidth: '1200px', margin: '0 auto', fontFamily: '"Inter", sans-serif' };
const topBar = { display: 'flex', justifyContent: 'space-between', marginBottom: '20px' };
const badgeLocal = { background: '#f1f5f9', padding: '6px 15px', borderRadius: '20px', fontSize: '0.8rem', fontWeight: '700' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' };
const titleStyle = { fontSize: '2rem', fontWeight: '900', margin: 0 };
const subtitleStyle = { color: '#64748b' };
const statsGrid = { display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '20px', marginBottom: '30px' };
const statCard = { background: 'white', padding: '20px', borderRadius: '15px', display: 'flex', alignItems: 'center', gap: '15px', border: '1px solid #f1f5f9' };
const statNum = { fontSize: '1.5rem', fontWeight: '900' };
const statLabel = { margin: 0, fontSize: '0.8rem', color: '#64748b' };

const publishBannerStyle = { background: '#0f172a', color: 'white', padding: '20px', borderRadius: '20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' };
const publishInfo = { display: 'flex', alignItems: 'center', gap: '20px' };
const pendingCountBadge = { background: '#f59e0b', padding: '5px 10px', borderRadius: '8px', fontSize: '0.8rem', fontWeight: '800' };
const dateInputGroup = { display: 'flex', flexDirection: 'column', gap: '4px' };
const dateLabel = { fontSize: '0.65rem', color: '#94a3b8', textTransform: 'uppercase' };
const dateInput = { background: '#1e293b', border: '1px solid #334155', color: 'white', padding: '6px', borderRadius: '8px', fontSize: '0.85rem' };
const btnPublicarMaster = { background: '#10b981', color: 'white', border: 'none', padding: '12px 20px', borderRadius: '12px', fontWeight: '800', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px' };

const searchBarContainer = { position: 'relative', marginBottom: '30px' };
const searchIcon = { position: 'absolute', left: '15px', top: '50%', transform: 'translateY(-50%)' };
const searchInput = { width: '100%', padding: '15px 15px 15px 45px', borderRadius: '12px', border: '1px solid #e2e8f0' };
const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '20px' };
const itemCard = { background: 'white', borderRadius: '20px', padding: '20px', border: '1px solid #f1f5f9', display: 'flex', flexDirection: 'column' };
const cardHeader = { display: 'flex', justifyContent: 'space-between', marginBottom: '15px' };

// ESTA ES LA QUE FALTABA
const cardBody = { flex: 1, display: 'flex', flexDirection: 'column', gap: '8px' };

const badgePublicado = { background: '#d1fae5', color: '#065f46', padding: '4px 8px', borderRadius: '6px', fontSize: '0.7rem', fontWeight: '800' };
const badgeBorrador = { background: '#f1f5f9', color: '#64748b', padding: '4px 8px', borderRadius: '6px', fontSize: '0.7rem', fontWeight: '800' };
const badgeStockIn = { fontSize: '0.7rem', color: '#64748b' };
const badgeStockOut = { fontSize: '0.7rem', color: '#ef4444', fontWeight: '800' };
const prodName = { margin: '0 0 5px 0', fontSize: '1.1rem', fontWeight: '800' };
